{
  "applicable_policies": [
    {
      "doc_id": "01_expense_reimbursement_2025.md",
      "title": "XX证券费用报销管理办法(2025修订版)",
      "clauses": [
        {
          "clause_no": "第十条",
          "summary": "同一发票最多报销1次。发现同一发票在不同报销单中重复出现的，应认定为重复报销风险。",
          "applicable_reason": "用于判断R004234和R004235是否使用同一发票构成重复报销"
        },
        {
          "clause_no": "第十一条",
          "summary": "不得将同一事项或同类事项拆分为多笔报销以规避审批权限。同一员工、同一费用类型在7天内出现2笔及以上报销，且合计金额达到《授权管理办法》附件二较高审批线的，应重点核查拆分规避审批。",
          "applicable_reason": "用于判断R004234和R004235是否构成拆分报销"
        }
      ],
      "policy_status": "施行中",
      "effective_date": "2025-01-01",
      "expiry_date": null
    },
    {
      "doc_id": "03_authorization_management.md",
      "title": "XX证券授权管理办法",
      "clauses": [
        {
          "clause_no": "附件二",
          "summary": "费用报销审批权限表：AR-01(0-3000,部门经理); AR-02(3000-10000,部门经理+财务复核); AR-03(10000-50000,部门总经理); AR-04(50000-200000,分管副总); AR-05(≥200000,总经理办公会)",
          "applicable_reason": "第十一条引用的审批线标准来源"
        }
      ],
      "policy_status": "施行中",
      "effective_date": "2025-01-01",
      "expiry_date": null
    }
  ],
  "excluded_policies": [
    {
      "doc_id": "02_expense_reimbursement_2022_deprecated.md",
      "reason": "已由2025版废止，报销发生在2025年10月"
    },
    {
      "doc_id": "07_office_communication.md",
      "reason": "办公用品月度600元标准为本任务范围外规则，仅作为背景信息"
    }
  ],
  "version_relationships": [],
  "conflicts": [],
  "unresolved_items": []
}

